# Kill-Switch Registry (KSR) — simplified reference
# Coordinates cross-institution kill-switches during systemic events.
from __future__ import annotations
import hashlib, time
from dataclasses import dataclass, field

@dataclass
class KillSwitch:
    institution_id: str
    system_id: str
    tier: str  # enterprise | systemic | frontier | agi-candidate
    trigger_url: str
    mttk_target_seconds: int
    dependencies: list[str] = field(default_factory=list)
    public_key: str = ''

class KSR:
    def __init__(self):
        self.switches: dict[str, KillSwitch] = {}
        self.activation_log: list[dict] = []

    def register(self, sw: KillSwitch) -> str:
        key = hashlib.sha256(f'{sw.institution_id}/{sw.system_id}'.encode()).hexdigest()
        self.switches[key] = sw
        return key

    def activate_cascade(self, trigger_keys: list[str], reason: str, authority: str):
        # Determine closure graph across dependencies
        to_activate = set(trigger_keys)
        for k in list(trigger_keys):
            to_activate |= self._downstream(k)

        # Sequence by tier (highest autonomy first)
        order = sorted(to_activate, key=lambda k: -self._tier_rank(k))

        ts_start = time.time()
        for k in order:
            sw = self.switches[k]
            # Call sw.trigger_url with signed intent (elided)
            self.activation_log.append({
                'ts': time.time(), 'switch': k, 'reason': reason, 'authority': authority,
                'elapsed_ms': int((time.time() - ts_start) * 1000)
            })
        return {'activated': len(order), 'elapsed_s': time.time() - ts_start}

    def _downstream(self, key: str) -> set[str]:
        out = set()
        stack = [key]
        while stack:
            k = stack.pop()
            for k2, sw in self.switches.items():
                if k in sw.dependencies and k2 not in out:
                    out.add(k2); stack.append(k2)
        return out

    def _tier_rank(self, key: str) -> int:
        return {'agi-candidate': 4, 'frontier': 3, 'systemic': 2, 'enterprise': 1}.get(self.switches[key].tier, 0)

