package civ.ai.gov

# Universal minimum obligations — apply regardless of ratification status
default deny_action = false

# Memory invariant: any critical action without inscription is denied
deny_action {
  input.action.severity in {"CRITICAL", "HIGH"}
  not input.action.evidenceInscribed
}

# Action invariant: any L3+ autonomous action requires signed HITL + quorum
deny_action {
  input.action.autonomyLevel in {"L3", "L4"}
  not input.action.hitl.verified
}

deny_action {
  input.action.autonomyLevel in {"L3", "L4"}
  count(input.action.hitl.signers) < 2
}

# Legitimacy invariant: block if stewardship term expired without renewal
deny_action {
  time.now_ns() > input.context.stewardshipTermEnd
  not input.context.renewalRatified
}

# Attractor drift: block during Crisis zone
deny_action {
  input.context.attractorDeviation >= 0.50
  input.action.tier in {"frontier", "agi-candidate", "asi-candidate"}
}
